	@SkipForDialect( dialectClass = FirebirdDialect.class, reason = "Firebird returns 2025-03-31 as a result of select {2024-02-29} + 13 month")
	public void testDurationArithmetic(SessionFactoryScope scope) {
		scope.inTransaction(
				session -> {
