	@Test
	public void testIn(SessionFactoryScope scope) {
		scope.inTransaction(
				session -> {
					assertEquals( 1,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameterList("list",List.of(1,2))
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameterList("list",List.of(0,3,2))
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameterList("list",List.of())
									.list().size() );
					assertEquals( 1,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameter("list",List.of(1))
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameter("list",List.of())
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in (:list)", Integer.class)
									.setParameter("list",null)
									.list().size() );
					assertEquals( 1,
							session.createQuery("select 1 where 1 in :list", Integer.class)
									.setParameterList("list",List.of(1,2))
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in :list", Integer.class)
									.setParameterList("list",List.of(0,3,2))
									.list().size() );
					assertEquals( 0,
							session.createQuery("select 1 where 1 in :list", Integer.class)
									.setParameterList("list",List.of())
									.list().size() );
					assertEquals( 0,
							session.createQuery( "select e from EntityWithOneToOne e where e.other in (:list)" )
									.setParameter( "list", null )
									.list().size() );
				}
		);
	}


